export function getNewYorkWeightLossClinicsByCity(citySlug: string): WeightLossClinic[] {
  return newYorkWeightLossClinics.filter(c => c.citySlug === citySlug);
}

export function getNewYorkWeightLossCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of newYorkWeightLossClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
